    async_stream::try_stream! {
        let mut upstream = response.bytes_stream();
        let mut decoder = SseDecoder::default();
        let mut current_model = fallback_model;

        while let Some(chunk) = upstream.next().await {
            let chunk = chunk?;
            decoder.push(&chunk);

