            self.status_message = "No profile selected.".to_owned();
            return Ok(());
        };
        let providers = ProviderHub::new(paths.clone());
        runtime.block_on(async { providers.logout(&profile).await })?;
        self.reload(paths)?;
        self.status_message = format!("Logged out {}", profile.name);
