use std::io;

use anyhow::{Result, anyhow, bail};
use arboard::Clipboard;
use crossterm::{
    event::{self, Event, KeyCode, KeyEvent, KeyModifiers},
    execute,
    terminal::{EnterAlternateScreen, LeaveAlternateScreen, disable_raw_mode, enable_raw_mode},
};
use gunmetal_core::{
    KeyScope, NewGunmetalKey, NewProviderProfile, ProviderKind, ProviderLoginSession,
    ProviderProfile,
};
use gunmetal_providers::builtin_provider_hub;
use gunmetal_storage::AppPaths;
use ratatui::{
    Frame, Terminal,
    backend::CrosstermBackend,
    layout::{Constraint, Direction, Layout, Rect},
    style::{Color, Modifier, Style},
    text::{Line, Span, Text},
    widgets::{Block, Borders, Clear, List, ListItem, ListState, Paragraph, Tabs, Wrap},
};
use tokio::runtime::Runtime;

pub fn run(paths: &AppPaths, service: ServiceSnapshot) -> Result<()> {
    let runtime = tokio::runtime::Builder::new_current_thread()
        .enable_all()
        .build()?;
    let mut app = DashboardApp::load(paths, service)?;
    let mut stdout = io::stdout();
    enable_raw_mode()?;
    execute!(stdout, EnterAlternateScreen)?;
    let backend = CrosstermBackend::new(stdout);
    let mut terminal = Terminal::new(backend)?;

    let result = run_loop(&mut terminal, &runtime, &mut app, paths);

    disable_raw_mode()?;
    execute!(terminal.backend_mut(), LeaveAlternateScreen)?;
    terminal.show_cursor()?;
    result
}

fn run_loop(
    terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
    runtime: &Runtime,
    app: &mut DashboardApp,
    paths: &AppPaths,
) -> Result<()> {
    loop {
        terminal.draw(|frame| render(frame, app))?;

        if let Event::Key(key) = event::read()?
            && app.handle_key(key, runtime, paths)?
        {
            break Ok(());
        }
    }
}

async fn start_browser_auth_via_service(
    service_url: &str,
    profile_id: uuid::Uuid,
) -> Result<ProviderLoginSession> {
    let client = reqwest::Client::new();
    let response = client
        .post(format!("{service_url}/app/api/profiles/{profile_id}/auth"))
        .send()
        .await?;
    let response_status = response.status();
    let body = response.json::<serde_json::Value>().await?;
    if !response_status.is_success() {
        let message = body
            .get("error")
            .and_then(|value| value.get("message"))
            .and_then(|value| value.as_str())
            .unwrap_or("auth request failed");
        bail!(message.to_owned());
    }

    Ok(ProviderLoginSession {
        login_id: "daemon-flow".to_owned(),
        auth_url: body
            .get("auth_url")
            .and_then(|value| value.as_str())
            .unwrap_or_default()
            .to_owned(),
        user_code: body
            .get("user_code")
            .and_then(|value| value.as_str())
            .map(ToOwned::to_owned),
        interval_seconds: None,
    })
}

fn render(frame: &mut Frame, app: &DashboardApp) {
    let area = frame.area();
    let rows = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(4),
            Constraint::Min(14),
            Constraint::Length(2),
        ])
        .split(area);

    let service_color = if app.service.running {
        Color::Green
    } else {
        Color::Yellow
    };
    let header = Paragraph::new(vec![
        Line::from(Span::styled(
            "Gunmetal",
            Style::default()
                .fg(Color::Cyan)
                .add_modifier(Modifier::BOLD),
        )),
        Line::from(format!(
            "{}  {}  {}",
            app.service.state, app.service.url, app.snapshot.root
        )),
        Line::from(vec![
            Span::raw("Service "),
            Span::styled(
                app.service.state.clone(),
                Style::default().fg(service_color),
            ),
            Span::raw(format!(
                "   Profiles {}   Keys {}   Logs {}",
                app.snapshot.profiles.len(),
                app.snapshot.keys.len(),
                app.snapshot.logs.len()
            )),
        ]),
    ])
    .block(Block::default().borders(Borders::ALL).title("Overview"));
    frame.render_widget(header, rows[0]);

    let body = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([Constraint::Percentage(36), Constraint::Percentage(64)])
        .split(rows[1]);

    let tabs = Tabs::new(Tab::titles())
        .select(app.tab.index())
        .block(Block::default().borders(Borders::ALL).title("Mode"))
        .highlight_style(
            Style::default()
                .fg(Color::Black)
                .bg(Color::Cyan)
                .add_modifier(Modifier::BOLD),
        );
    frame.render_widget(tabs, body[0]);

    let left = inner_area(body[0], 1, 3);
    match app.tab {
        Tab::Profiles => render_profiles_list(frame, app, left),
        Tab::Keys => render_keys_list(frame, app, left),
        Tab::Logs => render_logs_list(frame, app, left),
        Tab::Snippets => render_snippets_list(frame, app, left),
    }

    let detail = Paragraph::new(app.detail_text())
        .wrap(Wrap { trim: false })
        .block(
            Block::default()
                .borders(Borders::ALL)
                .title(app.tab.detail_title()),
        );
    frame.render_widget(detail, body[1]);

    let footer = Paragraph::new(vec![
        Line::from(app.hints()),
        Line::from(app.status_message.clone()),
    ])
    .block(Block::default().borders(Borders::ALL).title("Operator"));
    frame.render_widget(footer, rows[2]);

    if let Some(prompt) = &app.prompt {
        let area = centered_rect(64, 40, frame.area());
        frame.render_widget(Clear, area);
        let body = vec![
            Line::from(format!(
                "{} ({}/{})",
                prompt.current_label(),
                prompt.index + 1,
                prompt.fields.len()
            )),
            Line::from(""),
            Line::from(prompt.current_value()),
            Line::from(""),
            Line::from("Enter next field   Esc cancel   Backspace delete"),
        ];
        let prompt = Paragraph::new(body)
            .wrap(Wrap { trim: false })
            .block(Block::default().borders(Borders::ALL).title("New Profile"));
        frame.render_widget(prompt, area);
    }
}

fn render_profiles_list(frame: &mut Frame, app: &DashboardApp, area: Rect) {
    let items = if app.snapshot.profiles.is_empty() {
        vec![ListItem::new(
            "No profiles yet. Press n here or run `gunmetal setup`.",
        )]
    } else {
        app.snapshot
            .profiles
            .iter()
            .map(|item| {
                ListItem::new(format!(
