          radial-gradient(circle at top left, rgba(216, 178, 110, 0.16), transparent 34%),
          radial-gradient(circle at top right, rgba(125, 211, 200, 0.12), transparent 28%),
          linear-gradient(180deg, #0d1013, var(--bg) 34%);
      }

      a {
        color: inherit;
      }

      button,
      input,
      select {
        font: inherit;
      }

      .shell {
        width: min(1480px, calc(100vw - 32px));
        margin: 0 auto;
        padding: 20px 0 56px;
      }

      .masthead {
        display: grid;
        gap: 20px;
        padding: 20px 0 28px;
      }

      .brand-row,
      .status-row,
      .command-row,
      .section-grid {
        display: grid;
        gap: 16px;
      }

      .brand-row {
        grid-template-columns: minmax(0, 1.35fr) minmax(360px, 0.65fr);
      }

      .hero,
      .hero-side,
      .panel {
        border: 1px solid var(--line);
        border-radius: var(--radius);
        background: linear-gradient(180deg, var(--panel), var(--panel-2));
        box-shadow: var(--shadow);
        backdrop-filter: blur(18px);
      }

      .hero {
        position: relative;
        overflow: hidden;
        padding: 28px;
      }

      .hero::before {
        content: "";
        position: absolute;
        inset: 0;
        background:
          linear-gradient(120deg, rgba(216, 178, 110, 0.16), transparent 32%),
          radial-gradient(circle at 80% 10%, rgba(125, 211, 200, 0.16), transparent 24%);
        pointer-events: none;
      }

      .eyebrow {
        font-size: 12px;
        letter-spacing: 0.24em;
        text-transform: uppercase;
        color: var(--accent);
        margin: 0 0 12px;
      }

      h1,
      h2,
      h3,
      p {
        margin: 0;
      }

      h1 {
        max-width: 11ch;
        font-size: clamp(3rem, 8vw, 6.4rem);
        line-height: 0.9;
        letter-spacing: -0.04em;
      }

      .lede {
        max-width: 34rem;
        margin-top: 16px;
        font-size: clamp(1rem, 2vw, 1.18rem);
        line-height: 1.45;
        color: rgba(244, 244, 238, 0.84);
      }

      .hero-actions,
      .mini-actions,
      .provider-list,
      .count-grid {
        display: flex;
        flex-wrap: wrap;
        gap: 10px;
      }

      .hero-actions {
        margin-top: 22px;
      }

      .btn,
      .ghost-btn {
        border: 1px solid var(--line-strong);
        border-radius: 999px;
        padding: 10px 14px;
        color: var(--text);
        background: rgba(255, 255, 255, 0.04);
        cursor: pointer;
        transition: transform 0.16s ease, border-color 0.16s ease, background 0.16s ease;
      }

      .btn:hover,
      .ghost-btn:hover {
        transform: translateY(-1px);
        border-color: rgba(216, 178, 110, 0.58);
      }

      .btn.primary {
        background: linear-gradient(135deg, rgba(216, 178, 110, 0.2), rgba(216, 178, 110, 0.08));
        border-color: rgba(216, 178, 110, 0.48);
      }

      .hero-side,
      .panel {
        padding: 20px;
      }

      .hero-side {
        display: grid;
        gap: 14px;
        align-content: start;
      }

      .status-row {
        grid-template-columns: repeat(4, minmax(0, 1fr));
      }

      .stat {
        padding: 18px;
        border: 1px solid var(--line);
        border-radius: 20px;
        background: rgba(255, 255, 255, 0.02);
      }

      .stat-label {
        font-size: 12px;
        text-transform: uppercase;
        letter-spacing: 0.18em;
        color: var(--muted);
      }

      .stat-value {
        margin-top: 8px;
        font-size: clamp(1.8rem, 3.6vw, 3rem);
        line-height: 0.94;
      }

      .command-row {
        grid-template-columns: minmax(0, 1.2fr) minmax(320px, 0.8fr);
      }

      .panel-kicker {
        font-size: 11px;
        text-transform: uppercase;
        letter-spacing: 0.22em;
        color: var(--muted);
      }

      .mono {
        font-family: "IBM Plex Mono", "SFMono-Regular", ui-monospace, monospace;
      }

      .command-block {
        margin-top: 14px;
        padding: 14px;
        border-radius: 18px;
        border: 1px solid var(--line);
        background: rgba(0, 0, 0, 0.26);
        overflow: auto;
      }

      .section-grid {
        grid-template-columns: minmax(0, 0.86fr) minmax(340px, 0.74fr);
        align-items: start;
      }

      .stack {
        display: grid;
        gap: 16px;
      }

      .profile-grid {
        display: grid;
        gap: 14px;
      }

      .profile-card {
        border: 1px solid var(--line);
        border-radius: 22px;
        padding: 18px;
        background: rgba(255, 255, 255, 0.02);
      }

      .profile-meta,
      .key-meta {
        display: flex;
        flex-wrap: wrap;
        gap: 10px;
        margin-top: 10px;
      }

      .pill {
        border-radius: 999px;
        padding: 6px 10px;
        background: rgba(255, 255, 255, 0.04);
        border: 1px solid var(--line);
        font-size: 13px;
        color: var(--muted);
      }

