    </style>
  </head>
  <body>
    <div class="shell">
      <header class="masthead">
        <div class="brand-row">
          <section class="hero">
            <p class="eyebrow">Gunmetal Web</p>
            <h1>Local control. Browser comfort.</h1>
            <p class="lede">
              Same daemon. Same keys. Same provider state. This is the browser
              face of Gunmetal, served straight from your local gateway.
            </p>
            <div class="hero-actions">
