              <span class="subtle">Reading profiles, models, keys, and recent logs from your local Gunmetal home.</span>
            </div>
            <div class="banner success" id="secret-banner" hidden></div>
          </aside>
        </div>
        <section class="status-row" id="count-grid"></section>
        <section class="command-row">
          <article class="panel">
            <p class="panel-kicker">Golden path</p>
