          </article>
          <article class="panel">
            <p class="panel-kicker">Service</p>
            <div class="stack" id="service-panel"></div>
          </article>
        </section>
      </header>

      <main class="section-grid">
        <section class="stack">
          <article class="panel">
            <p class="panel-kicker">Profiles</p>
            <div id="profiles"></div>
          </article>
          <article class="panel">
            <p class="panel-kicker">Recent logs</p>
            <div id="logs"></div>
          </article>
        </section>
        <section class="stack">
          <article class="panel">
            <p class="panel-kicker">Create profile</p>
            <p class="note">
              Start with one provider. Browser-login providers open an auth URL.
              Key-based providers need the upstream API key saved here.
            </p>
            <form id="profile-form">
              <label>
                Provider
                <select name="provider">
                  <option value="codex">codex</option>
                  <option value="copilot">copilot</option>
                  <option value="openrouter">openrouter</option>
                  <option value="zen">zen</option>
                  <option value="openai">openai</option>
                  <option value="azure">azure</option>
                  <option value="nvidia">nvidia</option>
                </select>
              </label>
              <label>
                Profile name
                <input name="name" placeholder="work-openai" required />
              </label>
              <label>
                Base URL
                <input name="base_url" placeholder="optional override" />
              </label>
              <label>
                API key
                <input name="api_key" placeholder="optional for browser-login providers" />
              </label>
              <button class="btn primary" type="submit">Save profile</button>
            </form>
          </article>
          <article class="panel">
            <p class="panel-kicker">Keys</p>
            <div id="keys"></div>
