          <article class="panel">
            <p class="panel-kicker">Models</p>
            <div id="models"></div>
          </article>
        </section>
      </main>
    </div>

    <script>
      const appState = {
        data: null,
        banner: null,
      };

      const $ = (id) => document.getElementById(id);

      function escapeHtml(value) {
        return String(value ?? "")
          .replaceAll("&", "&amp;")
          .replaceAll("<", "&lt;")
          .replaceAll(">", "&gt;")
          .replaceAll('"', "&quot;");
      }

      function setBanner(message, tone = "default") {
        appState.banner = { message, tone };
        renderBanner();
      }

      function renderBanner() {
        const banner = $("message-banner");
        if (!appState.banner) {
          return;
        }
        const { message, tone } = appState.banner;
        banner.className = "banner";
        if (tone === "danger") banner.classList.add("danger");
        if (tone === "success") banner.classList.add("success");
        banner.innerHTML = `<strong>${tone === "danger" ? "Action failed." : "Updated."}</strong><span>${escapeHtml(message)}</span>`;
      }

      function setSecret(secret) {
        const banner = $("secret-banner");
        if (!secret) {
          banner.hidden = true;
          banner.innerHTML = "";
          return;
        }
        banner.hidden = false;
        banner.innerHTML = `<strong>New key secret</strong><span class="mono">${escapeHtml(secret)}</span>`;
      }

      function syncBanner(data) {
        if (appState.banner) {
          renderBanner();
          return;
        }
        if (!data.profiles.length) {
          $("message-banner").className = "banner";
          $("message-banner").innerHTML =
            "<strong>Ready.</strong><span class=\"subtle\">Create a profile, auth it, sync models, mint a key.</span>";
          return;
        }

        if (!data.models.length) {
          $("message-banner").className = "banner";
          $("message-banner").innerHTML =
            "<strong>Profile saved.</strong><span class=\"subtle\">Sync models next so apps can target explicit provider/model ids.</span>";
          return;
        }

        if (!data.keys.length) {
          $("message-banner").className = "banner success";
          $("message-banner").innerHTML =
            "<strong>Models are ready.</strong><span class=\"subtle\">Mint a Gunmetal key next, then point one app at the local API.</span>";
          return;
        }

        if (!data.logs.length) {
          $("message-banner").className = "banner success";
          $("message-banner").innerHTML =
            "<strong>Ready for traffic.</strong><span class=\"subtle\">Use the local base URL and one Gunmetal key in any OpenAI-compatible app.</span>";
          return;
        }

        $("message-banner").className = "banner success";
        $("message-banner").innerHTML =
          "<strong>Traffic flowing.</strong><span class=\"subtle\">Review recent logs below or keep refining keys and provider coverage.</span>";
      }

      async function fetchJson(url, options) {
        const response = await fetch(url, {
          headers: { "Content-Type": "application/json" },
          ...options,
        });
        const text = await response.text();
        const body = text ? JSON.parse(text) : {};
        if (!response.ok) {
          throw new Error(body?.error?.message || body?.message || "request failed");
        }
        return body;
      }

      async function loadState() {
        try {
          const data = await fetchJson("/app/api/state");
          appState.data = data;
          render();
        } catch (error) {
          setBanner(error.message, "danger");
        }
      }

      function render() {
        const data = appState.data;
        if (!data) return;
        const apiBaseUrl = new URL(data.service.api_base_url, window.location.origin).toString();
        const webUrl = new URL(data.service.web_url, window.location.origin).toString();
        syncBanner(data);

        $("provider-strip").innerHTML = data.providers
          .map(
            (provider) =>
              `<span class="pill">${escapeHtml(provider.kind)} · ${escapeHtml(provider.class)}</span>`,
          )
          .join("");

        $("count-grid").innerHTML = [
          ["Profiles", data.counts.profiles],
          ["Models", data.counts.models],
          ["Keys", data.counts.keys],
          ["Logs", data.counts.logs],
        ]
          .map(
            ([label, value]) => `
              <article class="stat">
                <div class="stat-label">${escapeHtml(label)}</div>
                <div class="stat-value">${escapeHtml(value)}</div>
              </article>
            `,
          )
          .join("");

        $("command-block").innerHTML = escapeHtml(
          [
            "npm i -g @dhruv2mars/gunmetal",
            "gunmetal setup",
            "gunmetal web",
            "",
            "OPENAI_BASE_URL=" + apiBaseUrl,
            "OPENAI_API_KEY=gm_your_local_key",
            "MODEL=provider/model",
          ].join("\n"),
        );

        $("service-panel").innerHTML = `
          <div><strong>Status</strong><div class="subtle">${escapeHtml(data.service.status)}</div></div>
          <div><strong>Version</strong><div class="subtle mono">${escapeHtml(data.service.version)}</div></div>
          <div><strong>Web</strong><div class="subtle mono">${escapeHtml(webUrl)}</div></div>
          <div><strong>API</strong><div class="subtle mono">${escapeHtml(apiBaseUrl)}</div></div>
          <div><strong>Home</strong><div class="subtle mono">${escapeHtml(data.service.home)}</div></div>
        `;

        $("profiles").innerHTML = data.profiles.length
          ? `<div class="profile-grid">${data.profiles
              .map(
                (profile) => `
                <article class="profile-card">
                  <h3>${escapeHtml(profile.name)}</h3>
                  <div class="profile-meta">
                    <span class="pill">${escapeHtml(profile.provider)}</span>
                    <span class="pill">${escapeHtml(profile.auth_label)}</span>
                    <span class="pill">${escapeHtml(profile.model_count)} models</span>
                  </div>
                  <p class="note mono">${escapeHtml(profile.selector)}${profile.base_url ? ` · ${escapeHtml(profile.base_url)}` : ""}</p>
                  <div class="profile-actions">
                    <button class="ghost-btn" type="button" onclick="profileAction('${profile.id}', 'auth')">Auth / Check</button>
                    <button class="ghost-btn" type="button" onclick="profileAction('${profile.id}', 'sync')">Sync models</button>
                    <button class="ghost-btn" type="button" onclick="createKey('${profile.id}')">Create key</button>
                    <button class="ghost-btn" type="button" onclick="profileAction('${profile.id}', 'logout')">Logout</button>
                    <button class="ghost-btn" type="button" onclick="deleteProfile('${profile.id}')">Delete</button>
                  </div>
                </article>
              `,
              )
              .join("")}</div>`
          : `<p class="note">No profiles yet. Save one on the right, then auth and sync it here.</p>`;

        $("keys").innerHTML = data.keys.length
          ? `<table class="table">
              <thead>
                <tr>
                  <th>Name</th>
                  <th>State</th>
                  <th>Providers</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                ${data.keys
                  .map(
                    (key) => `
                    <tr>
                      <td><strong>${escapeHtml(key.name)}</strong><div class="subtle mono">${escapeHtml(key.prefix)}</div></td>
                      <td>${escapeHtml(key.state)}</td>
                      <td>${escapeHtml(key.providers.length ? key.providers.join(", ") : "all")}</td>
                      <td>
                        <div class="key-actions">
                          <button class="ghost-btn" type="button" onclick="setKeyState('${key.id}', 'disabled')">Disable</button>
                          <button class="ghost-btn" type="button" onclick="setKeyState('${key.id}', 'revoked')">Revoke</button>
                          <button class="ghost-btn" type="button" onclick="deleteKey('${key.id}')">Delete</button>
                        </div>
                      </td>
                    </tr>
