                        <td>${escapeHtml(model.provider)}</td>
                        <td>${escapeHtml(model.supports_reasoning == null ? "unknown" : model.supports_reasoning ? "yes" : "no")}</td>
                      </tr>
                    `,
                  )
                  .join("")}
              </tbody>
            </table>`
          : `<p class="note">No models synced yet. Sync at least one profile.</p>`;

        $("logs").innerHTML = data.logs.length
          ? `<table class="table">
              <thead>
                <tr>
                  <th>When</th>
                  <th>Model</th>
                  <th>Result</th>
                  <th>Latency</th>
                </tr>
              </thead>
              <tbody>
                ${data.logs
                  .map(
                    (log) => `
                      <tr>
                        <td><div>${escapeHtml(log.profile_name || log.provider)}</div><div class="subtle mono">${escapeHtml(log.started_at)}</div></td>
                        <td><strong>${escapeHtml(log.model)}</strong><div class="subtle">${escapeHtml(log.endpoint)}</div></td>
                        <td>${escapeHtml(log.status_code ?? "pending")}${log.error_message ? `<div class="subtle">${escapeHtml(log.error_message)}</div>` : ""}</td>
                        <td>${escapeHtml(log.duration_ms)} ms${log.total_tokens ? `<div class="subtle">${escapeHtml(log.total_tokens)} tokens</div>` : ""}</td>
                      </tr>
                    `,
                  )
                  .join("")}
              </tbody>
            </table>`
          : `<p class="note">No request history yet. Point one app at Gunmetal, then come back.</p>`;
      }

      async function submitAction(url, options) {
        try {
          const body = await fetchJson(url, options);
          if (body.auth_url) {
            window.open(body.auth_url, "_blank", "noopener,noreferrer");
          }
          setBanner(body.message, "success");
          setSecret(body.secret || null);
          await loadState();
        } catch (error) {
          setBanner(error.message, "danger");
        }
      }

      async function profileAction(id, action) {
        await submitAction(`/app/api/profiles/${id}/${action}`, { method: "POST" });
      }

      async function createKey(id) {
        const chosen = window.prompt("Key name", "gunmetal-key");
        if (chosen == null) return;
        await submitAction(`/app/api/profiles/${id}/keys`, {
          method: "POST",
          body: JSON.stringify({ name: chosen }),
        });
      }

      async function setKeyState(id, state) {
        await submitAction(`/app/api/keys/${id}/state`, {
          method: "POST",
          body: JSON.stringify({ state }),
        });
      }

      async function deleteKey(id) {
        if (!window.confirm("Delete this key?")) return;
        await submitAction(`/app/api/keys/${id}`, { method: "DELETE" });
      }

      async function deleteProfile(id) {
        if (!window.confirm("Delete this profile and its synced models?")) return;
        await submitAction(`/app/api/profiles/${id}`, { method: "DELETE" });
      }

      $("profile-form").addEventListener("submit", async (event) => {
        event.preventDefault();
        const form = new FormData(event.currentTarget);
        await submitAction("/app/api/profiles", {
          method: "POST",
          body: JSON.stringify({
            provider: form.get("provider"),
            name: form.get("name"),
            base_url: form.get("base_url"),
            api_key: form.get("api_key"),
          }),
        });
        event.currentTarget.reset();
      });

      $("refresh-button").addEventListener("click", () => {
        appState.banner = null;
        setSecret(null);
        loadState();
      });

      $("copy-api-button").addEventListener("click", async () => {
        const base = appState.data
          ? new URL(appState.data.service.api_base_url, window.location.origin).toString()
          : null;
        if (!base) return;
        await navigator.clipboard.writeText(base);
        setBanner("Copied API base URL.", "success");
      });

      loadState();
    </script>
  </body>
</html>

