async fn invoke_provider(
    state: &DaemonState,
    key: GunmetalKey,
    profile: ProviderProfile,
    request: ChatCompletionRequest,
    endpoint: &'static str,
) -> Result<ChatCompletionResult, Response> {
    let started_at = Instant::now();
    match state.providers.chat_completion(&profile, &request).await {
        Ok(result) => {
            let duration_ms = started_at.elapsed().as_millis() as u64;
            state.request_logger.log(NewRequestLogEntry {
                key_id: Some(key.id),
                profile_id: Some(profile.id),
                provider: profile.provider,
                model: request.model,
                endpoint: endpoint.to_owned(),
                status_code: Some(StatusCode::OK.as_u16()),
                duration_ms,
                usage: result.usage.clone(),
                error_message: None,
            });
            Ok(result)
        }
        Err(error) => {
            let duration_ms = started_at.elapsed().as_millis() as u64;
            state.request_logger.log(NewRequestLogEntry {
                key_id: Some(key.id),
                profile_id: Some(profile.id),
                provider: profile.provider,
                model: request.model,
                endpoint: endpoint.to_owned(),
                status_code: Some(StatusCode::BAD_GATEWAY.as_u16()),
                duration_ms,
                usage: TokenUsage {
                    input_tokens: None,
                    output_tokens: None,
                    total_tokens: None,
                },
                error_message: Some(error.to_string()),
            });
            Err(api_error(
                StatusCode::BAD_GATEWAY,
                "provider_request_failed",
                format!(
                    "Provider request failed for profile '{}'. Check `gunmetal auth status {}` and retry. Upstream said: {}",
                    profile.name, profile.name, error
                ),
            ))
        }
    }
}

