async fn invoke_provider(
    state: &DaemonState,
    key: GunmetalKey,
    profile: ProviderProfile,
    request: ChatCompletionRequest,
    endpoint: &'static str,
) -> Result<ChatCompletionResult, Response> {
    let started_at = Instant::now();
    match state.providers.chat_completion(&profile, &request).await {
        Ok(result) => {
            let duration_ms = started_at.elapsed().as_millis() as u64;
            state.request_logger.log(NewRequestLogEntry {
                key_id: Some(key.id),
                profile_id: Some(profile.id),
                provider: profile.provider,
                model: request.model,
                endpoint: endpoint.to_owned(),
                status_code: Some(StatusCode::OK.as_u16()),
                duration_ms,
                usage: result.usage.clone(),
                error_message: None,
            });
            Ok(result)
        }
        Err(error) => {
            let duration_ms = started_at.elapsed().as_millis() as u64;
            state.request_logger.log(NewRequestLogEntry {
                key_id: Some(key.id),
                profile_id: Some(profile.id),
                provider: profile.provider,
                model: request.model,
                endpoint: endpoint.to_owned(),
                status_code: Some(StatusCode::BAD_GATEWAY.as_u16()),
                duration_ms,
                usage: TokenUsage {
                    input_tokens: None,
                    output_tokens: None,
                    total_tokens: None,
                },
                error_message: Some(error.to_string()),
            });
            Err(api_error(
                StatusCode::BAD_GATEWAY,
                "provider_request_failed",
                format!(
                    "Provider request failed for profile '{}'. Check `gunmetal auth status {}` and retry. Upstream said: {}",
                    profile.name, profile.name, error
                ),
            ))
        }
    }
}

async fn invoke_provider_stream(
    state: &DaemonState,
    key: GunmetalKey,
    profile: ProviderProfile,
    request: ChatCompletionRequest,
    endpoint: &'static str,
) -> Result<ProviderEventStream, Response> {
    let started_at = Instant::now();
    let request_model = request.model.clone();

    match state
        .providers
        .stream_chat_completion(&profile, &request)
        .await
    {
        Ok(mut provider_stream) => {
            let request_logger = state.request_logger.clone();
            let key_id = key.id;
            let profile_id = profile.id;
            let provider = profile.provider.clone();
            let endpoint_name = endpoint.to_owned();

            Ok(async_stream::try_stream! {
                let mut logged = false;
                while let Some(item) = provider_stream.next().await {
                    match item {
                        Ok(ProviderStreamEvent::Complete { model, finish_reason, usage }) => {
                            if !logged {
                                logged = true;
                                request_logger.log(NewRequestLogEntry {
                                    key_id: Some(key_id),
                                    profile_id: Some(profile_id),
                                    provider: provider.clone(),
                                    model: request_model.clone(),
                                    endpoint: endpoint_name.clone(),
                                    status_code: Some(StatusCode::OK.as_u16()),
                                    duration_ms: started_at.elapsed().as_millis() as u64,
                                    usage: usage.clone(),
                                    error_message: None,
                                });
                            }

                            yield ProviderStreamEvent::Complete {
                                model,
                                finish_reason,
                                usage,
                            };
                        }
                        Ok(event) => yield event,
                        Err(error) => {
                            if !logged {
                                logged = true;
                                request_logger.log(NewRequestLogEntry {
                                    key_id: Some(key_id),
                                    profile_id: Some(profile_id),
                                    provider: provider.clone(),
                                    model: request_model.clone(),
                                    endpoint: endpoint_name.clone(),
                                    status_code: Some(StatusCode::BAD_GATEWAY.as_u16()),
                                    duration_ms: started_at.elapsed().as_millis() as u64,
                                    usage: TokenUsage {
                                        input_tokens: None,
                                        output_tokens: None,
                                        total_tokens: None,
                                    },
                                    error_message: Some(error.to_string()),
                                });
                            }

                            Err::<(), anyhow::Error>(error)?;
                        }
                    }
                }

                if !logged {
                    request_logger.log(NewRequestLogEntry {
                        key_id: Some(key_id),
                        profile_id: Some(profile_id),
                        provider,
                        model: request_model,
                        endpoint: endpoint_name,
                        status_code: Some(StatusCode::OK.as_u16()),
                        duration_ms: started_at.elapsed().as_millis() as u64,
                        usage: TokenUsage {
                            input_tokens: None,
                            output_tokens: None,
                            total_tokens: None,
                        },
                        error_message: None,
                    });
                }
            }
            .boxed())
        }
        Err(error) => {
            state.request_logger.log(NewRequestLogEntry {
                key_id: Some(key.id),
                profile_id: Some(profile.id),
                provider: profile.provider,
                model: request.model,
                endpoint: endpoint.to_owned(),
                status_code: Some(StatusCode::BAD_GATEWAY.as_u16()),
                duration_ms: started_at.elapsed().as_millis() as u64,
                usage: TokenUsage {
                    input_tokens: None,
                    output_tokens: None,
                    total_tokens: None,
                },
                error_message: Some(error.to_string()),
            });
            Err(api_error(
                StatusCode::BAD_GATEWAY,
                "provider_request_failed",
                format!(
                    "Provider request failed for profile '{}'. Check `gunmetal auth status {}` and retry. Upstream said: {}",
                    profile.name, profile.name, error
                ),
            ))
        }
    }
}

