fn require_profile(state: &DaemonState, id: Uuid) -> Result<ProviderProfile, ApiError> {
    state
        .storage
        .get_profile(id)
        .map_err(internal_api_error)?
        .ok_or_else(|| {
            ApiError::new(
                StatusCode::NOT_FOUND,
                "profile_not_found",
                "provider not found".to_owned(),
            )
        })
}

