      const $ = (id) => document.getElementById(id);

      function escapeHtml(value) {
        return String(value ?? "")
          .replaceAll("&", "&amp;")
          .replaceAll("<", "&lt;")
          .replaceAll(">", "&gt;")
          .replaceAll('"', "&quot;");
      }

      function formatTimestamp(value) {
        if (!value) return "";
        const date = new Date(value);
        return Number.isNaN(date.getTime()) ? value : date.toLocaleString();
      }

      function setBanner(message, tone = "default") {
        appState.banner = { message, tone };
        renderBanner();
      }

      function renderBanner() {
        const banner = $("message-banner");
        if (!appState.banner) {
          return;
        }
        const { message, tone } = appState.banner;
        banner.className = "banner";
        if (tone === "danger") banner.classList.add("danger");
        if (tone === "success") banner.classList.add("success");
        banner.innerHTML = `<strong>${tone === "danger" ? "Action failed." : "Updated."}</strong><span>${escapeHtml(message)}</span>`;
      }

      function setSecret(secret) {
        const banner = $("secret-banner");
        if (!secret) {
          banner.hidden = true;
          banner.innerHTML = "";
          return;
        }
        banner.hidden = false;
        banner.innerHTML = `<strong>New key secret</strong><span class="mono">${escapeHtml(secret)}</span>`;
      }

      function syncBanner(data) {
        if (appState.banner) {
          renderBanner();
          return;
        }
        if (!data.profiles.length) {
          $("message-banner").className = "banner";
          $("message-banner").innerHTML =
