              <article class="setup-step${done ? " done" : ""}">
                <strong>${escapeHtml(label)}</strong>
                <span>${detail}</span>
              </article>
            `,
          )
          .join("");

        $("traffic-grid").innerHTML = [
          [
            "Total tokens",
            data.traffic.total_tokens,
            `in ${escapeHtml(data.traffic.input_tokens)} · out ${escapeHtml(data.traffic.output_tokens)}`,
          ],
          [
            "Avg latency",
            data.traffic.avg_latency_ms == null ? "—" : `${escapeHtml(data.traffic.avg_latency_ms)} ms`,
            data.traffic.latest_request_at
              ? `latest ${escapeHtml(formatTimestamp(data.traffic.latest_request_at))}`
